-- Add a reusable 150-word shopping and payment deck with pre-generated audio.
insert into public.template_decks (slug, name, description, level)
values (
  'mua-sam-thanh-toan-150',
  'Mua sắm và thanh toán - 150 từ',
  '150 từ vựng tiếng Trung thực tế về giá cả, kích cỡ, khuyến mãi, đặt hàng, thanh toán điện tử, đổi trả và hoàn tiền. Mỗi từ có pinyin, nghĩa tiếng Việt, câu ví dụ theo ngữ cảnh và hai audio tạo sẵn.',
  'Mua sắm'
)
on conflict (slug) do update
set
  name = excluded.name,
  description = excluded.description,
  level = excluded.level;

with target_deck as (
  select id
  from public.template_decks
  where slug = 'mua-sam-thanh-toan-150'
)
insert into public.template_cards (
  template_deck_id,
  chinese,
  pinyin,
  meaning_vi,
  example_cn,
  example_pinyin,
  example_vi,
  word_audio_url,
  sentence_audio_url,
  position
)
select
  target_deck.id,
  card.chinese,
  card.pinyin,
  card.meaning_vi,
  card.example_cn,
  card.example_pinyin,
  card.example_vi,
  card.word_audio_url,
  card.sentence_audio_url,
  card.position
from target_deck
cross join (
  values
    ('超市', 'chāoshì', 'siêu thị', '我在超市买水果和日用品。', 'Wǒ zài chāoshì mǎi shuǐguǒ hé rìyòngpǐn.', 'Tôi mua trái cây và đồ dùng hàng ngày ở siêu thị.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/mua-sam-thanh-toan-150/word-fc63db3dd42214b418cf4838.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/mua-sam-thanh-toan-150/sentence-5940cb9e05bad2c001fc6343.mp3', 1),
